1	import { useCallback, useRef, useState } from "react";
2	import type { SelectableEntity, SelectionZoneId } from "../types";
3	import { useGlobalSelectionStore } from "../../../store/globalSelectionStore";
4	
5	interface Rect {
6	  top: number;
7	  left: number;
8	  width: number;
9	  height: number;
10	}
11	
12	interface Props {
13	  zoneId: SelectionZoneId;
14	  enumerate: () => Array<{ entity: SelectableEntity; rect: Rect }>;
15	  containerRef: React.RefObject<HTMLElement>;
16	}
17	
18	export function MarqueeLayer({ zoneId, enumerate, containerRef }: Props) {
19	  const [rect, setRect] = useState<Rect | null>(null);
20	  const modeRef = useRef<"add" | "toggle" | "remove" | "replace">("replace");
21	  const startRef = useRef<{ x: number; y: number } | null>(null);
22	  const selectMany = useGlobalSelectionStore((s) => s.selectMany);
23	  const clearZone = useGlobalSelectionStore((s) => s.clearZone);
24	
25	  const onMouseDown = useCallback(
26	    (e: React.MouseEvent) => {
27	      if (e.button !== 0) return;
28	      if (e.target !== containerRef.current) return;
29	      const bounds = containerRef.current!.getBoundingClientRect();
30	      startRef.current = {
31	        x: e.clientX - bounds.left,
32	        y: e.clientY - bounds.top,
33	      };
34	      modeRef.current = e.altKey
35	        ? "remove"
36	        : e.ctrlKey || e.metaKey
37	          ? "add"
38	          : "replace";
39	      setRect({
40	        top: startRef.current.y,
41	        left: startRef.current.x,
42	        width: 0,
43	        height: 0,
44	      });
45	    },
46	    [containerRef],
47	  );
48	
49	  const onMouseMove = useCallback(
50	    (e: React.MouseEvent) => {
51	      if (!startRef.current) return;
52	      const bounds = containerRef.current!.getBoundingClientRect();
53	      const x = e.clientX - bounds.left;
54	      const y = e.clientY - bounds.top;
55	      const left = Math.min(startRef.current.x, x);
56	      const top = Math.min(startRef.current.y, y);
57	      const width = Math.abs(x - startRef.current.x);
58	      const height = Math.abs(y - startRef.current.y);
59	      setRect({ top, left, width, height });
60	    },
61	    [containerRef],
62	  );
63	
64	  const onMouseUp = useCallback(() => {
65	    if (!rect) return;
66	    const contained = enumerate()
67	      .filter(({ rect: r }) => fullyContained(r, rect))
68	      .map(({ entity }) => entity);
69	    if (modeRef.current === "replace") {
70	      if (contained.length === 0) clearZone(zoneId);
71	      else selectMany(zoneId, contained, "replace");
72	    } else if (modeRef.current === "add") {
73	      selectMany(zoneId, contained, "add");
74	    } else if (modeRef.current === "remove") {
75	      selectMany(zoneId, contained, "remove");
76	    }
77	    startRef.current = null;
78	    setRect(null);
79	  }, [rect, enumerate, selectMany, clearZone, zoneId]);
80	
81	  return (
82	    <div
83	      style={{ position: "absolute", inset: 0 }}
84	      onMouseDown={onMouseDown}
85	      onMouseMove={onMouseMove}
86	      onMouseUp={onMouseUp}
87	      onMouseLeave={() => {
88	        startRef.current = null;
89	        setRect(null);
90	      }}
91	    >
92	      {rect ? (
93	        <div
94	          style={{
95	            position: "absolute",
96	            top: rect.top,
97	            left: rect.left,
98	            width: rect.width,
99	            height: rect.height,
100	            background: "rgba(80, 180, 255, 0.08)",
101	            border: "1px dashed var(--accent)",
102	            pointerEvents: "none",
103	          }}
104	        />
105	      ) : null}
106	    </div>
107	  );
108	}
109	
110	function fullyContained(inner: Rect, outer: Rect): boolean {
111	  return (
112	    inner.left >= outer.left &&
113	    inner.top >= outer.top &&
114	    inner.left + inner.width <= outer.left + outer.width &&
115	    inner.top + inner.height <= outer.top + outer.height
116	  );
117	}
